function welcomePopper(){let t=Date.now()+3e3,e={startVelocity:30,spread:360,ticks:60,zIndex:0};function n(t,e){return Math.random()*(e-t)+t}let o=setInterval((function(){let r=t-Date.now();if(r<=0)return clearInterval(o);let a=r/3e3*50;confetti({...e,particleCount:a,origin:{x:n(.1,.3),y:Math.random()-.2}}),confetti({...e,particleCount:a,origin:{x:n(.7,.9),y:Math.random()-.2}})}),250)}$(document).ready((async function(){null===localStorage.getItem("first_visit")&&(localStorage.setItem("first_visit",!1),welcomePopper())}));